        "code": "#include <iostream>\n#include <map>\n#include <vector>\n#include <string>\nusing namespace std;\n\n// Document = map of key-value pairs (like JSON)\nusing Document = map<string, string>;\n\nclass DocumentDB {\n    map<string, Document> collection;\n    int nextId = 1;\npublic:\n    // Insert a document\n    string insert(Document doc) {\n        string id = \"doc_\" + to_string(nextId++);\n        doc[\"_id\"] = id;\n        collection[id] = doc;\n        return id;\n    }\n    \n    // Find by field value\n    vector<Document> findWhere(string field, string value) {\n        vector<Document> results;\n        for (auto& [id, doc] : collection) {\n            if (doc.count(field) && doc.at(field) == value)\n                results.push_back(doc);\n        }\n        return results;\n    }\n};\n\nint main() {\n    DocumentDB db;\n    \n    // Insert documents (like MongoDB)\n    db.insert({{\"name\",\"Ahmed\"},{\"city\",\"Cairo\"},{\"role\",\"developer\"}});\n    db.insert({{\"name\",\"Sara\"},{\"city\",\"Alex\"},{\"role\",\"designer\"}});\n    db.insert({{\"name\",\"Omar\"},{\"city\",\"Cairo\"},{\"role\",\"developer\"}});\n    \n    // Find all developers in Cairo\n    auto results = db.findWhere(\"role\", \"developer\");\n    cout << \"Developers:\\n\";\n    for (auto& doc : results)\n        cout << \"  \" << doc.at(\"name\") << \" from \" << doc.at(\"city\") << \"\\n\";\n    \n    return 0;\n}",
